[SRSReportParameterAttribute(classStr(ETGGMCReportContractNew))]
internal final class ETGGMCReportDPNew extends SrsReportDataProviderPreProcessTempDB
{
    ETGGMCTableTemp etggmctableTemp, etggmctableTempCheck, gmrReportTempZeroQty, gmrReportTempPositiveQty,gmrContractQty;
    Notes strSalesDiscount, strPurchaseDiscount, strSDCost, strDirectCost, strMmFV, strMmSIT, strOtherIncome, strInsuranceClaimRecId;
    Notes strTotalCost, strRealisedExchangeAdjustment, strGC, strDepreciation, strAdminCostAndBankCharges, strStaffCost, strUnrealizedForex, strOtherCost, strEBITDA, strOtherFinCosts, strInterestIncome, strInterestExpense, strNetEBITDA;

    str reportName = 'GMR';
    container conSalesDiscount, conPurchaseDiscount, conSDCost, conDirectCost, conMmFV, conMmSIT, conOtherIncome, conInsuranceClaimRecId;
    container conTotalCost, conRealisedExchangeAdjustment, conGC, conDepreciation, conAdminCostAndBankCharges, conStaffCost, conUnrealizedForex, conOtherCost, conEBITDA, conOtherFinCosts, conInterestIncome, conInterestExpense, conNetEBITDA;
    ETGACFParameters                    acfParam;
    ETGGMCTableTempNonInvoice           ETGGMCTableTempNonInvoice;
    ETGGeneralJOurnalAccountEntryMMR    generalJournalAccountEntryMMR;
    ETGGMCTableTempNew                  gmrTableTempNew;

    FromDate fromDate;
    ToDate   toDate;

}

